import { Component, Element, Event, EventEmitter, Fragment, h, Listen, Prop, State } from '@stencil/core';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { customTwMerge, generateRandId } from '../../utils/utils';
import { getNavItemLinkRel } from '../../utils/nav-item-link';
import { NavItemMediumMediaSize, NavItemMediumMediaType, NavItemMediumClickDetail } from './wdpr-nav-item-medium.model';
import { getContainerClass, getLabelClass, getMediaClass } from './wdpr-nav-item-medium.utils';

@Component({
  tag: 'wdpr-nav-item-medium',
  shadow: true,
  styles: `
    :host([media-type='image']) ::slotted(*) {
      display: block;
      width: 100%;
      height: 100%;
      object-fit: cover;
    }
  `,
})
export class WdprNavItemMedium {
  @Element() el: HTMLWdprNavItemMediumElement;

  @State() private _hasMedia: boolean = false;
  @State() private _internalId: string;
  @State() private _isTwoLineClamp: boolean = false;

  /**
   * Size of the media element (only applies when mediaType is 'image')
   */
  @Prop({ reflect: true }) mediaSize: NavItemMediumMediaSize = 'medium';

  /**
   * Optional prop for custom label styling
   * Consistency across media types, as icons may require different label styling than images
   */
  @Prop() customLabelClass: string = '';
  @Prop({ reflect: true }) allowBoldText: boolean = false;

  @Prop() label!: string;
  @Prop({ reflect: true }) mediaType: NavItemMediumMediaType = 'image';
  @Prop({ reflect: true }) disabled: boolean = false;
  @Prop({ reflect: true }) inverse?: boolean = false;
  @Prop() itemId?: string;
  @Prop({ attribute: 'a11y-label' }) a11yLabel?: string;
  @Prop({ reflect: true }) href?: string;
  @Prop({ reflect: true }) target?: string;
  @Prop({ reflect: true }) rel?: string;

  @Event() wdprNavItemMediumClick: EventEmitter<NavItemMediumClickDetail>;

  private _labelElement?: HTMLDivElement;
  private _resizeObserver?: ResizeObserver;

  componentWillLoad() {
    this._updateSlots();
    this._internalId = this.itemId || `wdpr-nav-item-medium-${generateRandId()}`;
  }

  componentDidLoad() {
    this._updateClampState();

    if (typeof ResizeObserver !== 'undefined') {
      this._resizeObserver = new ResizeObserver(() => this._updateClampState());
      this._resizeObserver.observe(this.el);
    }
  }

  disconnectedCallback() {
    this._resizeObserver?.disconnect();
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key === KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  @Listen('window:resize')
  handleWindowResize() {
    this._updateClampState();
  }

  private get _containerClass(): string {
    return getContainerClass(this.disabled, this.inverse);
  }

  private get _accessibleLabel(): string {
    return this.a11yLabel || this.label;
  }

  private get _isNavLink(): boolean {
    return Boolean(this.href?.trim()) && !this.disabled;
  }

  private get _anchorClass(): string {
    return customTwMerge(this._containerClass, 'no-underline');
  }

  private get _labelClass(): string {
    return customTwMerge(
      getLabelClass(this.customLabelClass, this.allowBoldText),
      this._isTwoLineClamp && '!py-0 -mt-025',
    );
  }

  private get _mediaClass(): string {
    return customTwMerge('self-start', this.mediaType === 'image' && getMediaClass(this.mediaSize));
  }

  private _updateSlots = () => {
    const mediaSlot = this.el.querySelector('[slot="media"]');
    this._hasMedia = !!mediaSlot;
  };

  private _updateClampState = () => {
    if (!this._labelElement || typeof window === 'undefined') return;

    const lineHeight = Number.parseFloat(window.getComputedStyle(this._labelElement).lineHeight);
    const isTwoLineClamp = this._labelElement.scrollHeight > lineHeight * 1.5;

    if (isTwoLineClamp !== this._isTwoLineClamp) {
      this._isTwoLineClamp = isTwoLineClamp;
    }
  };

  private _onClick = () => {
    if (this.disabled) return;

    this.wdprNavItemMediumClick.emit(this._internalId);
  };

  private _onLinkClick = () => {
    if (this.disabled) return;
    this.wdprNavItemMediumClick.emit(this._internalId);
  };

  private _renderMedia() {
    if (!this._hasMedia) return null;

    if (this.mediaType === 'icon') {
      return (
        <div class={this._mediaClass}>
          <slot name="media" onSlotchange={this._updateSlots}></slot>
        </div>
      );
    }

    return (
      <div class={this._mediaClass}>
        <slot name="media" onSlotchange={this._updateSlots}></slot>
      </div>
    );
  }

  render() {
    const body = (
      <Fragment>
        {this._renderMedia()}
        <div class={this._labelClass} ref={el => (this._labelElement = el as HTMLDivElement)}>{this.label}</div>
      </Fragment>
    );

    if (this._isNavLink) {
      return (
        <a
          class={this._anchorClass}
          href={this.href!.trim()}
          id={this._internalId}
          aria-label={this._accessibleLabel}
          target={this.target}
          rel={getNavItemLinkRel(this.target, this.rel)}
          onClick={this._onLinkClick}
        >
          {body}
        </a>
      );
    }

    return (
      <button type="button" disabled={this.disabled} class={this._containerClass} aria-label={this._accessibleLabel} id={this._internalId} onClick={this._onClick}>
        {body}
      </button>
    );
  }
}
